import { useEffect, useState } from "react";
import axios from "axios";
import { Link } from "react-router-dom";

function Dashboard() {

  const token = localStorage.getItem("token");
  if (!token) {
    window.location.href = "/";
  }

  const user = JSON.parse(localStorage.getItem("user"));
  const [stats, setStats] = useState({});

  useEffect(() => {
    axios.get("http://localhost:5000/api/users/doctors")
      .then(res => {
        const data = res.data;
        const count = {};

        data.forEach(d => {
          count[d.specialization] = (count[d.specialization] || 0) + 1;
        });

        setStats(count);
      });
  }, []);

  const logout = () => {
    localStorage.clear();
    window.location.href = "/";
  };

  return (
    <div className="layout">

      <div className="sidebar">
        <h2>🏥 MediCare</h2>

        <Link to="/dashboard">🏠 Dashboard</Link>

        {user?.role === "patient" && (
          <>
            <Link to="/doctors">👨‍⚕️ Doctors</Link>
            <Link to="/book">📅 Book Appointment</Link>
          </>
        )}

        <Link to="/appointments">📋 Appointments</Link>

        <button onClick={logout}>🚪 Logout</button>
      </div>

      <div className="main">

        <div className="header">
          <h2>Welcome {user?.name} 👋</h2>
          <p>Role: {user?.role}</p>
        </div>

        {/* ✅ UPDATED CARDS SECTION */}
        <div className="cards">

          {/* Total Specializations */}
          <div className="card-box">
            <h3>Total Specializations</h3>
            <p>{Object.keys(stats).length}</p>
          </div>

          {/* Total Doctors */}
          <div className="card-box">
            <h3>Total Doctors</h3>
            <p>
              {Object.values(stats).reduce((a, b) => a + b, 0)}
            </p>
          </div>

          {/* Individual Specialization Cards */}
          {Object.keys(stats).map(key => (
            <div className="card-box" key={key}>
              <h3>{key}</h3>
              <p>{stats[key]} Doctors</p>
            </div>
          ))}

        </div>

      </div>
    </div>
  );
}

export default Dashboard;
